import functools
import os
import re
from abc import ABC, abstractmethod
from dataclasses import dataclass
from pathlib import Path
from typing import Any, ClassVar, Literal, override

from harbor.agents.base import BaseAgent
from harbor.environments.base import BaseEnvironment
from harbor.utils.env import parse_bool_env_value
from harbor.utils.templating import render_prompt_template


class NonZeroAgentExitCodeError(RuntimeError):
    """Raised when the agent process exits with a non-zero exit code."""

    pass


class ApiRateLimitError(NonZeroAgentExitCodeError):
    """Raised when a failed command's output indicates the model provider
    rate-limited a request.

    Subclasses NonZeroAgentExitCodeError so existing handlers keep catching
    it, while the distinct type name lets retry policy target it, e.g.
    ``harbor run --max-retries 3 --retry-include ApiRateLimitError``.
    """

    pass


class ApiUsageLimitError(NonZeroAgentExitCodeError):
    """Raised when a failed command's output indicates the model provider
    rejected the request because an account or project usage limit is exhausted.
    """

    pass


_F = Any  # Use Any to keep the decorator signature-transparent to type checkers


def with_prompt_template(fn: _F) -> _F:
    """Decorator for ``run()`` that applies prompt-template rendering.

    Usage::

        @with_prompt_template
        async def run(self, instruction, environment, context):
            # instruction is already rendered through the prompt template
            ...
    """

    @functools.wraps(fn)
    async def wrapper(
        self: BaseInstalledAgent, instruction: str, *args: Any, **kwargs: Any
    ) -> None:
        instruction = self.render_instruction(instruction)
        return await fn(self, instruction, *args, **kwargs)

    return wrapper


@dataclass
class CliFlag:
    """Declarative CLI flag that maps a kwarg to a command-line flag.

    Omitted kwargs use env_fallback/default values. Explicit ``None`` is treated
    as an opt-out and omits the flag.
    """

    kwarg: str
    cli: str
    type: Literal["str", "int", "bool", "enum"] = "str"
    choices: list[str] | None = None
    default: Any = None
    env_fallback: str | None = None
    format: str | None = None


@dataclass
class EnvVar:
    """Declarative env var that maps a kwarg to an environment variable."""

    kwarg: str
    env: str
    type: Literal["str", "int", "bool", "enum"] = "str"
    choices: list[str] | None = None
    default: Any = None
    env_fallback: str | None = None
    bool_true: str = "true"
    bool_false: str = "false"


@dataclass
class ErrorPattern:
    """Declarative regex that classifies failed command output into a
    specific error. Searched case-insensitively over stdout and stderr;
    first match wins, so declaration order is priority order."""

    pattern: str
    exception: type[NonZeroAgentExitCodeError]


def _coerce_value(
    value: Any,
    type: Literal["str", "int", "bool", "enum"],
    choices: list[str] | None,
    kwarg_name: str,
) -> Any:
    """Coerce a value to the specified type, raising ValueError on failure."""
    match type:
        case "str":
            if isinstance(value, bool):
                raise ValueError(
                    f"Invalid value for '{kwarg_name}': expected str, got bool"
                )
            if isinstance(value, (int, float)):
                return str(value)
            if not isinstance(value, str):
                raise ValueError(
                    f"Invalid value for '{kwarg_name}': expected str, got {value.__class__.__name__}"
                )
            return value

        case "int":
            if isinstance(value, bool):
                raise ValueError(
                    f"Invalid value for '{kwarg_name}': expected int, got bool"
                )
            if isinstance(value, int):
                return value
            if isinstance(value, float):
                if value != int(value):
                    raise ValueError(
                        f"Invalid value for '{kwarg_name}': float {value} is not an integer"
                    )
                return int(value)
            if isinstance(value, str):
                try:
                    return int(value)
                except ValueError:
                    raise ValueError(
                        f"Invalid value for '{kwarg_name}': cannot parse '{value}' as int"
                    )
            raise ValueError(
                f"Invalid value for '{kwarg_name}': expected int, got {value.__class__.__name__}"
            )

        case "bool":
            return parse_bool_env_value(value, name=kwarg_name)

        case "enum":
            if not isinstance(value, str):
                raise ValueError(
                    f"Invalid value for '{kwarg_name}': expected str for enum, got {value.__class__.__name__}"
                )
            normalized = value.strip().lower()
            if not choices:
                return normalized
            for choice in choices:
                if normalized == choice.lower():
                    return choice
            raise ValueError(
                f"Invalid value for '{kwarg_name}': '{value}'. "
                f"Valid values: {', '.join(sorted(choices))}"
            )

        case _:
            raise ValueError(f"Unknown type '{type}' for kwarg '{kwarg_name}'")


class BaseInstalledAgent(BaseAgent, ABC):
    """
    An interface for agents that are installed and run in the environment.
    """

    CLI_FLAGS: ClassVar[list[CliFlag]] = []
    ENV_VARS: ClassVar[list[EnvVar]] = []
    ERROR_PATTERNS: ClassVar[list[ErrorPattern]] = [
        ErrorPattern(r"rate.?limit", ApiRateLimitError),
        ErrorPattern(r"too many requests", ApiRateLimitError),
        ErrorPattern(r"specified API usage limits", ApiUsageLimitError),
    ]

    def __init__(
        self,
        logs_dir: Path,
        prompt_template_path: Path | str | None = None,
        version: str | None = None,
        extra_env: dict[str, str] | None = None,
        *args,
        **kwargs,
    ):
        # Auto-extract kwargs matching CLI_FLAGS and ENV_VARS descriptors
        self._flag_kwargs: dict[str, Any] = {}
        for descriptor in [*self.CLI_FLAGS, *self.ENV_VARS]:
            if descriptor.kwarg in kwargs:
                self._flag_kwargs[descriptor.kwarg] = kwargs.pop(descriptor.kwarg)

        super().__init__(logs_dir, *args, extra_env=extra_env, **kwargs)

        # Resolve and validate all descriptor values eagerly
        self._resolved_flags = self._resolve_flag_values()
        self._resolved_env_vars = self._resolve_env_values()
        self._compiled_error_patterns = [
            (re.compile(p.pattern, re.IGNORECASE), p.exception)
            for p in self.ERROR_PATTERNS
        ]

        self._prompt_template_path = (
            Path(prompt_template_path) if prompt_template_path else None
        )
        self._version = version

    def _resolve_raw_value(
        self,
        descriptor: CliFlag | EnvVar,
    ) -> Any:
        """Get the raw value for a descriptor from kwargs, then env_fallback, then default."""
        if descriptor.kwarg in self._flag_kwargs:
            return self._flag_kwargs[descriptor.kwarg]
        if descriptor.env_fallback and descriptor.env_fallback in os.environ:
            return os.environ[descriptor.env_fallback]
        return descriptor.default

    def _resolve_flag_values(self) -> dict[str, Any]:
        """Resolve all CLI_FLAGS to their final coerced values (non-None only)."""
        resolved: dict[str, Any] = {}
        for flag in self.CLI_FLAGS:
            raw = self._resolve_raw_value(flag)
            if raw is None:
                continue
            resolved[flag.kwarg] = _coerce_value(
                raw, flag.type, flag.choices, flag.kwarg
            )
        return resolved

    def build_cli_flags(self) -> str:
        """Build the CLI flags string from CLI_FLAGS descriptors.

        Returns a string like '--max-turns 5 --effort high' ready to insert into a command.
        """
        parts: list[str] = []
        for flag in self.CLI_FLAGS:
            value = self._resolved_flags.get(flag.kwarg)
            if value is None:
                continue
            if flag.format is not None:
                parts.append(flag.format.format(value=value))
            elif flag.type == "bool":
                if value:
                    parts.append(flag.cli)
            else:
                parts.append(f"{flag.cli} {value}")
        return " ".join(parts)

    def _resolve_env_values(self) -> dict[str, str]:
        """Resolve all ENV_VARS to their final {env_name: string_value} dict (non-None only)."""
        resolved: dict[str, str] = {}
        for env_var in self.ENV_VARS:
            raw = self._resolve_raw_value(env_var)
            if raw is None:
                continue
            coerced = _coerce_value(raw, env_var.type, env_var.choices, env_var.kwarg)
            if env_var.type == "bool":
                resolved[env_var.env] = (
                    env_var.bool_true if coerced else env_var.bool_false
                )
            else:
                resolved[env_var.env] = str(coerced)
        return resolved

    def resolve_env_vars(self) -> dict[str, str]:
        """Public access to resolved env vars dict."""
        return dict(self._resolved_env_vars)

    def _get_env(self, key: str) -> str | None:
        """Get env var from extra_env (priority) or os.environ."""
        if key in self._extra_env:
            return self._extra_env[key]
        return os.environ.get(key)

    def _has_env(self, key: str) -> bool:
        """Check if env var exists in extra_env or os.environ."""
        return key in self._extra_env or key in os.environ

    def _get_env_prefixed(self, prefix: str) -> dict[str, str]:
        """Get all env vars with prefix from extra_env and os.environ (extra_env wins)."""
        result: dict[str, str] = {}
        for key, value in os.environ.items():
            if key.startswith(prefix):
                result[key[len(prefix) :]] = value
        for key, value in self._extra_env.items():
            if key.startswith(prefix):
                result[key[len(prefix) :]] = value
        return result

    @override
    def version(self) -> str | None:
        return self._version

    def get_version_command(self) -> str | None:
        """Return a shell command that prints the agent version to stdout.
        Override in subclasses to enable auto-detection after setup."""
        return None

    def parse_version(self, stdout: str) -> str:
        """Parse the output of get_version_command into a version string.
        Override in subclasses if the command output needs parsing."""
        return stdout.strip()

    def _truncate_output(self, text: str | None, max_len: int = 1000) -> str:
        if not text:
            return "None"
        if len(text) > max_len:
            return text[:max_len] + " ... [truncated]"
        return text

    def _classify_exec_error(
        self, command: str, result: Any
    ) -> NonZeroAgentExitCodeError:
        """Map a failed command to the most specific error in ERROR_PATTERNS,
        falling back to NonZeroAgentExitCodeError.

        Override for non-regex classification (e.g. structured event parsing).
        """
        detail = (
            f"Command failed (exit {result.return_code}): {command}\n"
            f"stdout: {self._truncate_output(result.stdout)}\n"
            f"stderr: {self._truncate_output(result.stderr)}"
        )
        output = f"{result.stdout or ''}\n{result.stderr or ''}"
        for compiled, exception in self._compiled_error_patterns:
            if compiled.search(output):
                self.logger.debug(
                    f"Classified failed command as {exception.__name__} "
                    f"(pattern: {compiled.pattern!r})"
                )
                return exception(detail)
        return NonZeroAgentExitCodeError(detail)

    async def _exec(
        self,
        environment: BaseEnvironment,
        command: str,
        user: str | int | None = None,
        env: dict[str, str] | None = None,
        cwd: str | None = None,
        timeout_sec: int | None = None,
    ) -> Any:
        """Execute a command with logging and error handling.

        Agent ``extra_env`` is wired into the real environment by ``Trial`` with
        a scoped exec-env context. Keeping this method limited to per-exec env
        preserves one precedence rule for both installed and import-path agents.

        Returns the ExecResult on success, raises RuntimeError on failure.
        """
        self.logger.debug(
            f"Running command: {command}",
            extra={
                "user": str(user),
                "env": env or {},
            },
        )

        result = await environment.exec(
            command=f"set -o pipefail; {command}",
            user=user,
            env=env,
            cwd=cwd,
            timeout_sec=timeout_sec,
        )
        if result.return_code != 0:
            self.logger.debug(
                "Command failed",
                extra={
                    "return_code": result.return_code,
                    "stdout": self._truncate_output(result.stdout),
                    "stderr": self._truncate_output(result.stderr),
                },
            )
            raise self._classify_exec_error(command, result)

        self.logger.debug(
            "Command outputs captured",
            extra={
                "stdout": self._truncate_output(result.stdout),
                "stderr": self._truncate_output(result.stderr),
            },
        )
        return result

    async def exec_as_root(
        self,
        environment: BaseEnvironment,
        command: str,
        env: dict[str, str] | None = None,
        cwd: str | None = None,
        timeout_sec: int | None = None,
    ) -> Any:
        """Execute a command as root (for system packages, symlinks, etc.)."""
        return await self._exec(
            environment, command, user="root", env=env, cwd=cwd, timeout_sec=timeout_sec
        )

    async def exec_as_agent(
        self,
        environment: BaseEnvironment,
        command: str,
        env: dict[str, str] | None = None,
        cwd: str | None = None,
        timeout_sec: int | None = None,
    ) -> Any:
        """Execute a command as the default agent user."""
        return await self._exec(
            environment, command, env=env, cwd=cwd, timeout_sec=timeout_sec
        )

    def render_instruction(self, instruction: str) -> str:
        """Render the instruction through the prompt template, if configured."""
        if self._prompt_template_path:
            return render_prompt_template(self._prompt_template_path, instruction)
        return instruction

    @abstractmethod
    async def install(self, environment: BaseEnvironment) -> None:
        """Install the agent in the environment.

        Use ``exec_as_root`` for system packages and ``exec_as_agent``
        for user-level installs.
        """
        pass

    @override
    async def setup(self, environment: BaseEnvironment) -> None:
        await environment.exec(command="mkdir -p /installed-agent", user="root")

        setup_dir = self.logs_dir / "setup"
        setup_dir.mkdir(parents=True, exist_ok=True)

        try:
            await self.install(environment)
        except RuntimeError:
            raise
        except Exception as exc:
            raise RuntimeError(f"Agent install failed: {exc}") from exc

        if self._version is None:
            version_cmd = self.get_version_command()
            if version_cmd:
                try:
                    version_result = await environment.exec(command=version_cmd)
                    if version_result.return_code == 0 and version_result.stdout:
                        self._version = self.parse_version(version_result.stdout)
                except Exception:
                    pass  # Version detection is best-effort

import json
import shlex
from pathlib import Path, PurePosixPath
from typing import Any, Literal, override

from harbor.agents.installed.base import (
    BaseInstalledAgent,
    CliFlag,
    with_prompt_template,
)
from harbor.environments.base import BaseEnvironment
from harbor.models.agent.context import AgentContext
from harbor.models.agent.name import AgentName
from harbor.models.trajectories import (
    Agent,
    FinalMetrics,
    Metrics,
    Observation,
    ObservationResult,
    Step,
    ToolCall,
    Trajectory,
)
from harbor.models.trial.paths import EnvironmentPaths
from harbor.utils.env import parse_bool_env_value
from harbor.utils.trajectory_utils import format_trajectory_json


class Codex(BaseInstalledAgent):
    """
    The Codex agent uses OpenAI's Codex CLI tool to solve tasks.
    """

    SUPPORTS_ATIF: bool = True
    _OUTPUT_FILENAME = "codex.txt"
    _REMOTE_CODEX_HOME = PurePosixPath("/tmp/codex-home")
    _REMOTE_CODEX_SECRETS_DIR = PurePosixPath("/tmp/codex-secrets")
    _INSTALL_CHECK_COMMAND = (
        "if [ -s ~/.nvm/nvm.sh ]; then . ~/.nvm/nvm.sh; fi; "
        "command -v codex >/dev/null 2>&1"
    )
    _INSTALL_VERSION_COMMAND = (
        "if [ -s ~/.nvm/nvm.sh ]; then . ~/.nvm/nvm.sh; fi; codex --version"
    )

    CLI_FLAGS = [
        CliFlag(
            "reasoning_effort",
            cli="-c",
            type="str",
            default="high",
            format="-c model_reasoning_effort={value}",
        ),
        CliFlag(
            "reasoning_summary",
            cli="-c",
            type="enum",
            choices=["auto", "concise", "detailed", "none"],
            format="-c model_reasoning_summary={value}",
        ),
    ]

    @staticmethod
    @override
    def name() -> str:
        return AgentName.CODEX.value

    @property
    def _trajectory_path(self) -> PurePosixPath:
        return PurePosixPath(EnvironmentPaths.agent_dir / "trajectory.json")

    @override
    def get_version_command(self) -> str | None:
        return "if [ -s ~/.nvm/nvm.sh ]; then . ~/.nvm/nvm.sh; fi; codex --version"

    @override
    def parse_version(self, stdout: str) -> str:
        text = stdout.strip()
        for line in text.splitlines():
            line = line.strip()
            if line:
                return line.removeprefix("codex-cli").strip()
        return text

    async def _installed_codex_satisfies_version(
        self, environment: BaseEnvironment
    ) -> bool:
        if self._version is None:
            check_result = await environment.exec(command=self._INSTALL_CHECK_COMMAND)
            return check_result.return_code == 0

        version_result = await environment.exec(command=self._INSTALL_VERSION_COMMAND)
        if version_result.return_code != 0:
            return False

        installed_version = self.parse_version(version_result.stdout or "")
        return installed_version == self._version

    @override
    async def install(self, environment: BaseEnvironment) -> None:
        if await self._installed_codex_satisfies_version(environment):
            self.logger.debug("Codex is already available at the requested version")
            return

        # Install system packages (root)
        await self.exec_as_root(
            environment,
            command=(
                "if ldd --version 2>&1 | grep -qi musl || [ -f /etc/alpine-release ]; then"
                "  apk add --no-cache curl bash nodejs npm ripgrep;"
                " elif command -v apt-get &>/dev/null; then"
                "  apt-get update && apt-get install -y curl ripgrep;"
                " elif command -v yum &>/dev/null; then"
                "  yum install -y curl ripgrep;"
                " else"
                '  echo "Warning: No known package manager found, assuming curl is available" >&2;'
                " fi"
            ),
            env={"DEBIAN_FRONTEND": "noninteractive"},
        )
        # Install codex (as default user)
        version_spec = f"@{self._version}" if self._version else "@latest"
        await self.exec_as_agent(
            environment,
            command=(
                "set -euo pipefail; "
                "if ldd --version 2>&1 | grep -qi musl || [ -f /etc/alpine-release ]; then"
                f"  npm install -g @openai/codex{version_spec};"
                " else"
                "  curl -o- https://raw.githubusercontent.com/nvm-sh/nvm/v0.40.2/install.sh | bash &&"
                '  export NVM_DIR="$HOME/.nvm" &&'
                '  \\. "$NVM_DIR/nvm.sh" || true &&'
                "  command -v nvm &>/dev/null || { echo 'Error: NVM failed to load' >&2; exit 1; } &&"
                "  nvm install 22 && nvm alias default 22 && npm -v &&"
                f"  npm install -g @openai/codex{version_spec};"
                " fi && "
                "codex --version"
            ),
            env={"NVM_NODEJS_ORG_MIRROR": "https://nodejs.org/dist"},
        )
        # Symlink node/codex to /usr/local/bin (root)
        await self.exec_as_root(
            environment,
            command=(
                "for bin in node codex; do"
                '  BIN_PATH="$(which "$bin" 2>/dev/null || true)";'
                '  if [ -n "$BIN_PATH" ] && [ "$BIN_PATH" != "/usr/local/bin/$bin" ]; then'
                '    ln -sf "$BIN_PATH" "/usr/local/bin/$bin";'
                "  fi;"
                " done"
            ),
        )

    def _get_session_dir(self) -> Path | None:
        """Get the single session directory."""
        sessions_dir = self.logs_dir / "sessions"
        if not sessions_dir.exists():
            return None

        session_dirs = [d for d in sessions_dir.rglob("*") if d.is_dir()]
        if not session_dirs:
            return None
        max_depth = max(len(d.parts) for d in session_dirs)
        session_dirs = [d for d in session_dirs if len(d.parts) == max_depth]
        if not session_dirs:
            return None

        # Sanity check: there should be exactly one session
        if len(session_dirs) != 1:
            raise ValueError(f"Expected exactly 1 session, found {len(session_dirs)}")
        return session_dirs[0]

    @staticmethod
    def _extract_message_text(content: list[Any]) -> str:
        """Extract joined text from Codex content blocks."""
        parts: list[str] = []
        for block in content:
            if isinstance(block, dict):
                text = block.get("text")
                if isinstance(text, str):
                    parts.append(text)
        return "".join(parts)

    @staticmethod
    def _parse_output_blob(raw: Any) -> tuple[str | None, dict[str, Any] | None]:
        """Extract textual output and metadata from Codex tool outputs."""
        if raw is None:
            return None, None

        if isinstance(raw, str):
            try:
                parsed = json.loads(raw)
            except json.JSONDecodeError:
                return raw, None
        else:
            parsed = raw

        if isinstance(parsed, dict):
            output = parsed.get("output")
            if output is None and parsed:
                # dumping remaining structure if output missing
                output = json.dumps(parsed, ensure_ascii=False)
            metadata = parsed.get("metadata")
            return output, metadata if isinstance(metadata, dict) else None

        return str(parsed), None

    @staticmethod
    def _group_events_by_api_call_id(
        normalized_events: list[dict[str, Any]],
    ) -> list[dict[str, Any]]:
        """Merge assistant events from the same Codex model request into one step."""
        result: list[dict[str, Any]] = []
        groups: dict[str, dict[str, Any]] = {}
        group_order: list[str] = []

        def flush() -> None:
            for group_id in group_order:
                group = groups.pop(group_id, None)
                if group is None:
                    continue
                group["tool_calls"].sort(key=lambda tc: tc.get("tool_order", 0))
                message_parts = [
                    part
                    for part in group.pop("message_parts")
                    if isinstance(part, str) and part
                ]
                group["text"] = "\n\n".join(message_parts)
                result.append(group)
            group_order.clear()

        for event in normalized_events:
            api_call_id = event.get("api_call_id")
            kind = event.get("kind")
            role = event.get("role")

            if kind == "message" and role != "assistant":
                flush()
                result.append(event)
                continue

            if not isinstance(api_call_id, str):
                flush()
                result.append(event)
                continue

            if api_call_id not in groups:
                groups[api_call_id] = {
                    "kind": "bundled",
                    "api_call_id": api_call_id,
                    "codex_turn_id": event.get("codex_turn_id"),
                    "timestamp": event.get("timestamp"),
                    "message_parts": [],
                    "reasoning": None,
                    "tool_calls": [],
                    "metrics": event.get("metrics"),
                }
                group_order.append(api_call_id)

            group = groups[api_call_id]
            if kind == "message":
                text = event.get("text")
                if isinstance(text, str) and text:
                    group["message_parts"].append(text)
                if event.get("reasoning"):
                    group["reasoning"] = event["reasoning"]
                if event.get("timestamp"):
                    group["timestamp"] = event["timestamp"]
            elif kind == "tool_call":
                group["tool_calls"].append(event)
                if not group["reasoning"] and event.get("reasoning"):
                    group["reasoning"] = event["reasoning"]
                if not group.get("metrics") and event.get("metrics"):
                    group["metrics"] = event["metrics"]

        flush()
        return result

    @staticmethod
    def _metrics_from_token_count_payload(
        payload: dict[str, Any],
    ) -> dict[str, Any] | None:
        info = payload.get("info")
        if not isinstance(info, dict):
            return None

        last_usage = info.get("last_token_usage")
        if not isinstance(last_usage, dict):
            return None

        prompt_tokens = last_usage.get("input_tokens")
        completion_tokens = last_usage.get("output_tokens")
        cached_tokens = last_usage.get("cached_input_tokens")
        reasoning_tokens = last_usage.get("reasoning_output_tokens")
        total_tokens = last_usage.get("total_tokens")

        return {
            "prompt_tokens": prompt_tokens if prompt_tokens else None,
            "completion_tokens": completion_tokens or None,
            "cached_tokens": cached_tokens or None,
            "extra": {
                "reasoning_output_tokens": reasoning_tokens,
                "total_tokens": total_tokens,
            },
        }

    def _convert_event_to_step(self, event: dict[str, Any], step_id: int) -> Step:
        """Convert a normalized Codex event dictionary into an ATIF step."""
        kind = event.get("kind")
        timestamp = event.get("timestamp")

        if kind == "message":
            role = event.get("role", "user")
            text = event.get("text", "")
            reasoning = event.get("reasoning")
            source: Literal["system", "user", "agent"]
            if role == "assistant":
                source = "agent"
            elif role == "user":
                source = "user"
            else:
                source = "system"

            extra = event.get("extra")

            return Step(
                step_id=step_id,
                timestamp=timestamp,
                source=source,
                message=text,
                reasoning_content=reasoning
                if source == "agent" and reasoning
                else None,
                model_name=self.model_name
                if source == "agent" and self.model_name
                else None,
                llm_call_count=1 if source == "agent" else None,
                extra=extra if extra else None,
            )

        if kind == "tool_call":
            call_id = event.get("call_id", "")
            tool_name = event.get("tool_name", "")
            reasoning = event.get("reasoning")
            arguments = event.get("arguments") or {}
            if not isinstance(arguments, dict):
                arguments = {"value": arguments}

            tool_call = ToolCall(
                tool_call_id=call_id,
                function_name=tool_name,
                arguments=arguments,
            )

            observation: Observation | None = None
            output_text = event.get("output")
            if output_text is not None:
                observation = Observation(
                    results=[
                        ObservationResult(
                            source_call_id=call_id or None,
                            content=output_text,
                        )
                    ]
                )

            metrics_payload = event.get("metrics")
            metrics: Metrics | None = None
            if isinstance(metrics_payload, dict):
                metrics = Metrics(**metrics_payload)

            extra: dict[str, Any] | None = None
            metadata = event.get("metadata")
            if metadata:
                extra = {"tool_metadata": metadata}
            raw_arguments = event.get("raw_arguments")
            if raw_arguments:
                extra = extra or {}
                extra["raw_arguments"] = raw_arguments
            status = event.get("status")
            if status:
                extra = extra or {}
                extra["status"] = status
            api_call_id = event.get("api_call_id")
            if api_call_id:
                extra = extra or {}
                extra["api_call_id"] = api_call_id
            codex_turn_id = event.get("codex_turn_id")
            if codex_turn_id:
                extra = extra or {}
                extra["codex_turn_id"] = codex_turn_id

            message = event.get("message") or ""

            return Step(
                step_id=step_id,
                timestamp=timestamp,
                source="agent",
                message=message,
                tool_calls=[tool_call],
                observation=observation,
                model_name=self.model_name if self.model_name else None,
                reasoning_content=reasoning if reasoning else None,
                metrics=metrics,
                llm_call_count=1,
                extra=extra,
            )

        if kind == "bundled":
            text = event.get("text", "")
            reasoning = event.get("reasoning")

            tool_calls: list[ToolCall] = []
            observation_results: list[ObservationResult] = []
            for tc in event.get("tool_calls", []):
                call_id = tc.get("call_id", "")
                arguments = tc.get("arguments") or {}
                if not isinstance(arguments, dict):
                    arguments = {"value": arguments}

                tool_calls.append(
                    ToolCall(
                        tool_call_id=call_id,
                        function_name=tc.get("tool_name", ""),
                        arguments=arguments,
                    )
                )
                observation_results.append(
                    ObservationResult(
                        source_call_id=call_id or None,
                        content=tc.get("output"),
                    )
                )

            extra: dict[str, Any] | None = None
            api_call_id = event.get("api_call_id")
            if api_call_id:
                extra = {"api_call_id": api_call_id}
            codex_turn_id = event.get("codex_turn_id")
            if codex_turn_id:
                extra = extra or {}
                extra["codex_turn_id"] = codex_turn_id

            tool_details: dict[str, Any] = {}
            for tc in event.get("tool_calls", []):
                call_id = tc.get("call_id", "")
                details: dict[str, Any] = {}
                for source_key, target_key in (
                    ("metadata", "metadata"),
                    ("raw_arguments", "raw_arguments"),
                    ("status", "status"),
                ):
                    value = tc.get(source_key)
                    if value:
                        details[target_key] = value
                if details:
                    tool_details[call_id] = details
            if tool_details:
                extra = extra or {}
                extra["tool_call_details"] = tool_details

            observation = (
                Observation(results=observation_results)
                if observation_results
                else None
            )

            return Step(
                step_id=step_id,
                timestamp=event.get("timestamp"),
                source="agent",
                message=text,
                model_name=self.model_name if self.model_name else None,
                reasoning_content=reasoning if reasoning else None,
                tool_calls=tool_calls or None,
                observation=observation,
                metrics=Metrics(**event["metrics"]) if event.get("metrics") else None,
                llm_call_count=1,
                extra=extra,
            )

        raise ValueError(f"Unsupported event kind '{kind}'")

    def _compute_cost_from_pricing(
        self,
        prompt_tokens: int | None,
        completion_tokens: int | None,
        cached_tokens: int | None,
    ) -> float | None:
        """Compute total cost in USD from token counts via LiteLLM's pricing table.

        Codex CLI's session JSONL never includes a cost field, so we apply
        LiteLLM's per-token rates to the aggregated counts ourselves. Returns
        None when the model is missing from the table — caller should leave
        cost_usd unset rather than report a misleading $0.
        """
        if not self.model_name:
            return None

        try:
            import litellm
        except ImportError:
            self.logger.debug("litellm not available; leaving codex cost_usd as None")
            return None

        pricing: dict[str, Any] | None = None
        for key in (self.model_name, self.model_name.split("/", 1)[-1]):
            entry = litellm.model_cost.get(key)
            if entry:
                pricing = entry
                break

        if pricing is None:
            self.logger.debug(
                "No LiteLLM pricing entry for model '%s'; leaving codex "
                "cost_usd as None",
                self.model_name,
            )
            return None

        input_rate = pricing.get("input_cost_per_token") or 0.0
        output_rate = pricing.get("output_cost_per_token") or 0.0
        cache_read_rate = pricing.get("cache_read_input_token_cost", input_rate)
        if cache_read_rate is None:
            cache_read_rate = input_rate

        uncached_input = max(0, (prompt_tokens or 0) - (cached_tokens or 0))
        cached = cached_tokens or 0
        output = completion_tokens or 0

        return (
            uncached_input * input_rate
            + cached * cache_read_rate
            + output * output_rate
        )

    def _convert_events_to_trajectory(self, session_dir: Path) -> Trajectory | None:
        """Convert Codex session JSONL events into an ATIF trajectory."""
        session_files = list(session_dir.glob("*.jsonl"))

        if not session_files:
            self.logger.debug(f"No Codex session files found in {session_dir}")
            return None

        session_file = session_files[0]

        raw_events: list[dict[str, Any]] = []
        with open(session_file, "r") as handle:
            for line in handle:
                stripped = line.strip()
                if not stripped:
                    continue
                try:
                    raw_events.append(json.loads(stripped))
                except json.JSONDecodeError as exc:
                    self.logger.debug(
                        f"Skipping malformed JSONL line in {session_file}: {exc}"
                    )

        if not raw_events:
            return None

        session_meta = next(
            (e for e in raw_events if e.get("type") == "session_meta"), None
        )
        session_id = (
            session_meta.get("payload", {}).get("id")
            if session_meta and isinstance(session_meta, dict)
            else session_dir.name
        )

        agent_version = "unknown"
        agent_extra: dict[str, Any] | None = None
        default_model_name: str | None = None

        if session_meta:
            payload = session_meta.get("payload", {})
            agent_version = payload.get("cli_version") or agent_version
            extra: dict[str, Any] = {}
            for key in ("originator", "cwd", "git", "instructions"):
                value = payload.get(key)
                if value is not None:
                    extra[key] = value
            agent_extra = extra or None

        if agent_version == "unknown" and self._version:
            agent_version = self._version

        for event in raw_events:
            if event.get("type") == "turn_context":
                model_name = event.get("payload", {}).get("model")
                if isinstance(model_name, str):
                    default_model_name = model_name
                    break

        if default_model_name is None:
            default_model_name = self.model_name

        # normalize events to a structure suitable for conversion into Steps
        normalized_events: list[dict[str, Any]] = []
        pending_calls: dict[str, dict[str, Any]] = {}
        pending_reasoning: str | None = None
        codex_turn_id: str | None = None
        api_call_index = 1
        current_api_call_id = f"api_call_{api_call_index}"
        api_call_metrics: dict[str, dict[str, Any]] = {}
        saw_model_output_in_api_call = False
        tool_order_counter = 0

        def record_model_output() -> None:
            nonlocal saw_model_output_in_api_call
            saw_model_output_in_api_call = True

        def finish_api_call(token_count_payload: dict[str, Any]) -> None:
            nonlocal api_call_index, current_api_call_id, saw_model_output_in_api_call
            nonlocal tool_order_counter

            if not saw_model_output_in_api_call:
                return

            metrics = self._metrics_from_token_count_payload(token_count_payload)
            if metrics:
                api_call_metrics[current_api_call_id] = metrics

            api_call_index += 1
            current_api_call_id = f"api_call_{api_call_index}"
            saw_model_output_in_api_call = False
            tool_order_counter = 0

        for event in raw_events:
            etype = event.get("type")
            payload = event.get("payload", {})
            timestamp = event.get("timestamp")

            if etype == "event_msg" and isinstance(payload, dict):
                event_type = payload.get("type")
                if event_type in {"task_started", "turn_started"}:
                    turn_id = payload.get("turn_id")
                    codex_turn_id = turn_id if isinstance(turn_id, str) else None
                elif event_type in {"task_complete", "turn_complete", "turn_aborted"}:
                    codex_turn_id = None
                elif event_type == "token_count":
                    # A token_count event closes one model API call.
                    finish_api_call(payload)
                continue

            if etype == "turn_context":
                turn_id = payload.get("turn_id") if isinstance(payload, dict) else None
                if isinstance(turn_id, str) and codex_turn_id is None:
                    codex_turn_id = turn_id
                continue

            if etype != "response_item":
                continue

            payload_type = payload.get("type")
            if payload_type == "reasoning":
                summary = payload.get("summary")
                if isinstance(summary, list) and summary:
                    reasoning_parts: list[str] = []
                    for item in summary:
                        if isinstance(item, str):
                            reasoning_parts.append(item)
                        elif isinstance(item, dict):
                            text = item.get("text")
                            if isinstance(text, str):
                                reasoning_parts.append(text)
                    pending_reasoning = (
                        "\n".join(reasoning_parts) if reasoning_parts else None
                    )
                else:
                    pending_reasoning = None
                continue

            if payload_type == "message":
                content = payload.get("content", [])
                text = (
                    self._extract_message_text(content)
                    if isinstance(content, list)
                    else ""
                )
                normalized_events.append(
                    {
                        "kind": "message",
                        "api_call_id": current_api_call_id,
                        "codex_turn_id": codex_turn_id,
                        "timestamp": timestamp,
                        "role": payload.get("role", "user"),
                        "text": text,
                        "reasoning": pending_reasoning
                        if payload.get("role") == "assistant"
                        else None,
                    }
                )
                if payload.get("role") == "assistant":
                    record_model_output()
                pending_reasoning = None
                continue

            if payload_type == "web_search_call":
                action = payload.get("action") or {}
                action_type = action.get("type", "")
                arguments: dict[str, Any] = {"action_type": action_type}
                if "query" in action:
                    arguments["query"] = action["query"]
                if "queries" in action:
                    arguments["queries"] = action["queries"]
                if "url" in action:
                    arguments["url"] = action["url"]

                normalized_events.append(
                    {
                        "kind": "tool_call",
                        "api_call_id": current_api_call_id,
                        "codex_turn_id": codex_turn_id,
                        "tool_order": tool_order_counter,
                        "timestamp": timestamp,
                        "call_id": "",
                        "tool_name": "web_search_call",
                        "arguments": arguments,
                        "raw_arguments": None,
                        "reasoning": pending_reasoning,
                        "status": payload.get("status"),
                        "message": None,
                    }
                )
                tool_order_counter += 1
                record_model_output()
                pending_reasoning = None
                continue

            if payload_type in {"function_call", "custom_tool_call"}:
                call_id = payload.get("call_id")
                if not call_id:
                    continue

                raw_args_key = (
                    "arguments" if payload_type == "function_call" else "input"
                )
                raw_arguments = payload.get(raw_args_key)
                try:
                    parsed_args = json.loads(raw_arguments)
                except (json.JSONDecodeError, TypeError):
                    if isinstance(raw_arguments, str):
                        parsed_args = {"input": raw_arguments}
                    elif raw_arguments is None:
                        parsed_args = {}
                    else:
                        parsed_args = {"value": raw_arguments}

                pending_calls[call_id] = {
                    "kind": "tool_call",
                    "api_call_id": current_api_call_id,
                    "codex_turn_id": codex_turn_id,
                    "tool_order": tool_order_counter,
                    "timestamp": timestamp,
                    "call_id": call_id,
                    "tool_name": payload.get("name") or "",
                    "arguments": parsed_args,
                    "raw_arguments": raw_arguments,
                    "reasoning": pending_reasoning,
                    "status": payload.get("status"),
                    "message": None,
                }
                tool_order_counter += 1
                record_model_output()
                pending_reasoning = None
                continue

            if payload_type in {"function_call_output", "custom_tool_call_output"}:
                call_id = payload.get("call_id")
                output_text, metadata = self._parse_output_blob(payload.get("output"))

                call_info = pending_calls.pop(call_id, None) if call_id else None

                if call_info is None:
                    call_info = {
                        "kind": "tool_call",
                        "api_call_id": current_api_call_id,
                        "codex_turn_id": codex_turn_id,
                        "tool_order": tool_order_counter,
                        "timestamp": timestamp,
                        "call_id": call_id or "",
                        "tool_name": payload.get("name", "") or "",
                        "arguments": {},
                        "raw_arguments": None,
                        "reasoning": pending_reasoning,
                        "status": None,
                        "message": None,
                    }
                    tool_order_counter += 1

                call_info["output"] = output_text
                call_info["metadata"] = metadata
                call_info["timestamp"] = call_info.get("timestamp") or timestamp
                normalized_events.append(call_info)
                pending_reasoning = None
                continue

        for norm_event in normalized_events:
            event_api_call_id = norm_event.get("api_call_id")
            if (
                isinstance(event_api_call_id, str)
                and event_api_call_id in api_call_metrics
            ):
                norm_event["metrics"] = api_call_metrics[event_api_call_id]

        grouped_events = self._group_events_by_api_call_id(normalized_events)

        steps: list[Step] = []
        for idx, norm_event in enumerate(grouped_events, start=1):
            try:
                step = self._convert_event_to_step(norm_event, idx)
            except ValueError as exc:
                self.logger.debug(f"Skipping event during step conversion: {exc}")
                continue

            # Provide default model name if not set for agent steps
            if step.source == "agent" and not step.model_name and default_model_name:
                step.model_name = default_model_name

            steps.append(step)

        if not steps:
            self.logger.debug("No valid steps produced from Codex session")
            return None

        # Extract final metrics from the last token_count event with totals
        total_metrics: FinalMetrics | None = None
        for event in reversed(raw_events):
            if event.get("type") != "event_msg":
                continue
            payload = event.get("payload", {})
            if not isinstance(payload, dict) or payload.get("type") != "token_count":
                continue

            info = payload.get("info")
            if not isinstance(info, dict):
                continue

            total_usage = info.get("total_token_usage")
            if not isinstance(total_usage, dict):
                continue

            prompt_tokens = total_usage.get("input_tokens")
            completion_tokens = total_usage.get("output_tokens")
            reasoning_tokens = total_usage.get("reasoning_output_tokens")
            cached_tokens = total_usage.get("cached_input_tokens")
            overall_tokens = total_usage.get("total_tokens")

            # Codex CLI does not include cost in token_count events, so fall
            # back to LiteLLM's pricing table when the field is absent. Use
            # explicit `is None` checks so a legitimate $0 cost reported by
            # the CLI isn't mistaken for a missing field.
            total_cost_usd = info.get("total_cost")
            if total_cost_usd is None:
                total_cost_usd = info.get("cost_usd")
            if total_cost_usd is None:
                total_cost_usd = self._compute_cost_from_pricing(
                    prompt_tokens=prompt_tokens,
                    completion_tokens=completion_tokens,
                    cached_tokens=cached_tokens,
                )

            final_extra: dict[str, Any] | None = {
                "reasoning_output_tokens": reasoning_tokens,
                "total_tokens": overall_tokens,
                "last_token_usage": info.get("last_token_usage"),
            }

            total_metrics = FinalMetrics(
                total_prompt_tokens=prompt_tokens if prompt_tokens else None,
                total_completion_tokens=completion_tokens or None,
                total_cached_tokens=cached_tokens or None,
                total_cost_usd=total_cost_usd,
                total_steps=len(steps),
                extra=final_extra,
            )
            break

        trajectory = Trajectory(
            schema_version="ATIF-v1.7",
            session_id=session_id,
            agent=Agent(
                name="codex",
                version=agent_version,
                model_name=default_model_name,
                extra=agent_extra,
            ),
            steps=steps,
            final_metrics=total_metrics,
        )

        return trajectory

    @override
    def populate_context_post_run(self, context: AgentContext) -> None:
        """
        Populate the agent context after Codex finishes executing.

        Converts the Codex session JSONL file into an ATIF trajectory, persists it,
        and propagates usage metrics back to the Harbor context.
        """
        session_dir = self._get_session_dir()
        if not session_dir:
            self.logger.debug("No Codex session directory found")
            return

        try:
            trajectory = self._convert_events_to_trajectory(session_dir)
        except Exception:
            self.logger.exception("Failed to convert Codex events to trajectory")
            return

        if not trajectory:
            self.logger.debug("Failed to convert Codex session to trajectory")
            return

        trajectory_path = self.logs_dir / "trajectory.json"
        try:
            with open(trajectory_path, "w") as handle:
                handle.write(format_trajectory_json(trajectory.to_json_dict()))
            self.logger.debug(f"Wrote Codex trajectory to {trajectory_path}")
        except OSError as exc:
            self.logger.debug(
                f"Failed to write trajectory file {trajectory_path}: {exc}"
            )

        if trajectory.final_metrics:
            metrics = trajectory.final_metrics
            context.cost_usd = metrics.total_cost_usd
            context.n_input_tokens = metrics.total_prompt_tokens or 0
            context.n_cache_tokens = metrics.total_cached_tokens or 0
            context.n_output_tokens = metrics.total_completion_tokens or 0

    def _build_register_skills_command(self) -> str | None:
        """Return a shell command that copies skills to Codex's skills directory."""
        if not self.skills_dir:
            return None
        return (
            f"mkdir -p $HOME/.agents/skills && "
            f"cp -r {shlex.quote(self.skills_dir)}/* "
            f"$HOME/.agents/skills/ 2>/dev/null || true"
        )

    def _build_register_mcp_servers_command(self) -> str | None:
        """Return a shell command that writes MCP config to $CODEX_HOME/config.toml."""
        if not self.mcp_servers:
            return None
        lines: list[str] = []
        for server in self.mcp_servers:
            lines.append(f"[mcp_servers.{server.name}]")
            if server.transport == "stdio":
                cmd_parts = [server.command] + server.args if server.command else []
                lines.append(f'command = "{shlex.join(cmd_parts)}"')
            else:
                lines.append(f'url = "{server.url}"')
            lines.append("")
        escaped_config = shlex.quote("\n".join(lines))
        return f'echo {escaped_config} >> "$CODEX_HOME/config.toml"'

    def _resolve_auth_json_path(self) -> Path | None:
        """Resolve which auth.json to inject, if any.

        Defaults to None (OPENAI_API_KEY auth). Opt into auth.json auth via:
          - CODEX_AUTH_JSON_PATH=<path> → use that specific file
          - CODEX_FORCE_AUTH_JSON=<truthy> → use ~/.codex/auth.json
        """
        explicit = self._get_env("CODEX_AUTH_JSON_PATH")
        if explicit:
            p = Path(explicit)
            if not p.is_file():
                raise ValueError(
                    f"CODEX_AUTH_JSON_PATH points to non-existent file: {explicit}"
                )
            return p

        if parse_bool_env_value(
            self._get_env("CODEX_FORCE_AUTH_JSON"),
            name="CODEX_FORCE_AUTH_JSON",
            default=False,
        ):
            default = Path.home() / ".codex" / "auth.json"
            if not default.is_file():
                raise ValueError(
                    f"CODEX_FORCE_AUTH_JSON is set but {default} does not exist"
                )
            return default

        return None

    @with_prompt_template
    async def run(
        self, instruction: str, environment: BaseEnvironment, context: AgentContext
    ) -> None:
        escaped_instruction = shlex.quote(instruction)

        if not self.model_name:
            raise ValueError("Model name is required")

        model = self.model_name.split("/")[-1]

        # Build command with optional CLI config flags from descriptors.
        cli_flags = self.build_cli_flags()
        cli_flags_arg = (cli_flags + " ") if cli_flags else ""

        # Auth resolution:
        #   1. CODEX_AUTH_JSON_PATH=<path> → use that specific auth.json file
        #   2. CODEX_FORCE_AUTH_JSON=<truthy> → use ~/.codex/auth.json
        #   3. Default: use OPENAI_API_KEY
        auth_json_path = self._resolve_auth_json_path()

        remote_codex_home = self._REMOTE_CODEX_HOME.as_posix()
        remote_secrets_dir = self._REMOTE_CODEX_SECRETS_DIR.as_posix()
        remote_auth_path = (self._REMOTE_CODEX_SECRETS_DIR / "auth.json").as_posix()

        env: dict[str, str] = {
            "CODEX_HOME": remote_codex_home,
        }

        await self.exec_as_agent(
            environment,
            command=(
                f'mkdir -p "$CODEX_HOME" {shlex.quote(remote_secrets_dir)} '
                f"{shlex.quote(EnvironmentPaths.agent_dir.as_posix())}"
            ),
            env=env,
        )

        if auth_json_path:
            self.logger.debug("Codex auth: using auth.json from %s", auth_json_path)
            await environment.upload_file(auth_json_path, remote_auth_path)
            # upload_file copies as root; fix ownership so the agent user can read it
            if environment.default_user is not None:
                await self.exec_as_root(
                    environment,
                    command=f"chown {environment.default_user} {remote_auth_path}",
                )
            setup_command = (
                f'ln -sf {shlex.quote(remote_auth_path)} "$CODEX_HOME/auth.json"\n'
            )
        else:
            self.logger.debug("Codex auth: using OPENAI_API_KEY")
            env["OPENAI_API_KEY"] = self._get_env("OPENAI_API_KEY") or ""
            setup_command = (
                f"cat >{shlex.quote(remote_auth_path)} <<EOF\n"
                '{\n  "OPENAI_API_KEY": "${OPENAI_API_KEY}"\n}\nEOF\n'
                f"ln -sf {shlex.quote(remote_auth_path)} "
                '"$CODEX_HOME/auth.json"\n'
            )

        if openai_base_url := self._get_env("OPENAI_BASE_URL"):
            env["OPENAI_BASE_URL"] = openai_base_url

        # codex 0.118.0 only honors openai_base_url from config.toml, not the env var.
        config_toml_block = ""
        if openai_base_url:
            config_toml_block = (
                '\ncat >>"$CODEX_HOME/config.toml" <<TOML\n'
                'openai_base_url = "${OPENAI_BASE_URL}"\n'
                "TOML"
            )

        setup_command += config_toml_block

        skills_command = self._build_register_skills_command()
        if skills_command:
            setup_command += f"\n{skills_command}"

        mcp_command = self._build_register_mcp_servers_command()
        if mcp_command:
            setup_command += f"\n{mcp_command}"

        if setup_command.strip():
            await self.exec_as_agent(
                environment,
                command=setup_command,
                env=env,
            )
        try:
            await self.exec_as_agent(
                environment,
                command=(
                    "if [ -s ~/.nvm/nvm.sh ]; then . ~/.nvm/nvm.sh; fi; "
                    "codex exec "
                    "--dangerously-bypass-approvals-and-sandbox "
                    "--skip-git-repo-check "
                    f"--model {model} "
                    "--json "
                    "--enable unified_exec "
                    f"{cli_flags_arg}"
                    "-- "  # end of flags
                    f"{escaped_instruction} "
                    f"2>&1 </dev/null | tee {
                        EnvironmentPaths.agent_dir / self._OUTPUT_FILENAME
                    }"
                ),
                env=env,
            )
        finally:
            try:
                await self.exec_as_agent(
                    environment,
                    command=(
                        f"mkdir -p {EnvironmentPaths.agent_dir.as_posix()}\n"
                        'if [ -d "$CODEX_HOME/sessions" ]; then\n'
                        f"  rm -rf {
                            (EnvironmentPaths.agent_dir / 'sessions').as_posix()
                        }\n"
                        f'  cp -R "$CODEX_HOME/sessions" {
                            (EnvironmentPaths.agent_dir / "sessions").as_posix()
                        }\n'
                        "fi"
                    ),
                    env=env,
                )
            except Exception:
                pass
            # cleanup - best effort
            try:
                await self.exec_as_agent(
                    environment,
                    command=f'rm -rf {shlex.quote(remote_secrets_dir)} "$CODEX_HOME"',
                    env=env,
                )
            except Exception:
                pass

